-- Ken's Hardened V2 Fix

local b64_0xIl1IIl = {}
local char_0xIIIl11='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xII1lll=1,#char_0xIIIl11 do b64_0xIl1IIl[char_0xIIIl11:sub(i_0xII1lll,i_0xII1lll)] = i_0xII1lll - 1 end

function b64_0xIl1IIl.dec_0xl11lIl(d_0xlIlII1)
    d_0xlIlII1 = string.gsub(d_0xlIlII1, '[^'..char_0xIIIl11..'=]', '')
    local r_0xIlIIll = {}
    for i_0xII1lll=1, #d_0xlIlII1, 4 do
        local c_0x1I1IIl = b64_0xIl1IIl[d_0xlIlII1:sub(i_0xII1lll,i_0xII1lll)] or 0
        local c_0xIIl1lI = b64_0xIl1IIl[d_0xlIlII1:sub(i_0xII1lll+1,i_0xII1lll+1)] or 0
        local c_0xI1Illl, c_0xlIIl1I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xlIlII1:sub(i_0xII1lll+2,i_0xII1lll+2)
        if ch3 == "=" then has3 = false else c_0xI1Illl = b64_0xIl1IIl[ch3] or 0 end
        local ch4 = d_0xlIlII1:sub(i_0xII1lll+3,i_0xII1lll+3)
        if ch4 == "=" then has4 = false else c_0xlIIl1I = b64_0xIl1IIl[ch4] or 0 end
        local b_0xlIl1I1 = c_0x1I1IIl * (2^18) + c_0xIIl1lI * (2^12) + c_0xI1Illl * (2^6) + c_0xlIIl1I
        local b_0xl1l1Il = math.floor(b_0xlIl1I1 / (2^16)) % (2^8)
        local b_0xlII1II = math.floor(b_0xlIl1I1 / (2^8)) % (2^8)
        local b_0xIIlI11 = b_0xlIl1I1 % (2^8)
        table.insert(r_0xIlIIll, string.char(b_0xl1l1Il))
        if has3 then table.insert(r_0xIlIIll, string.char(b_0xlII1II)) end
        if has4 then table.insert(r_0xIlIIll, string.char(b_0xIIlI11)) end
    end
    return table.concat(r_0xIlIIll)
end


local function bxor_0xlII1II(a_0x1lIII1,b_0xlIIIlI)
    if bit32 then return bit32.bxor(a_0x1lIII1,b_0xlIIIlI) end
    local r_0xIlIlIl = 0
    for i_0xIIIIIl = 0, 7 do
        local x_0xIll1lI = a_0x1lIII1 % 2
        local y_0xI1IIIl = b_0xlIIIlI % 2
        if x_0xIll1lI ~= y_0xI1IIIl then r_0xIlIlIl = r_0xIlIlIl + (2^i_0xIIIIIl) end
        a_0x1lIII1 = math.floor(a_0x1lIII1 / 2)
        b_0xlIIIlI = math.floor(b_0xlIIIlI / 2)
    end
    return r_0xIlIlIl
end


local function bxor_str_0xIlIIlI(s_0xIlIIIl, k_0xllIlll)
    local r_0xlIllIl = {}
    for i_0x1IllIl=1, #s_0xIlIIIl do
        local b_0x1lI111 = string.byte(s_0xIlIIIl, i_0x1IllIl)
        local kb_0xl11IlI = string.byte(k_0xllIlll, (i_0x1IllIl-1) % #k_0xllIlll + 1)
        r_0xlIllIl[i_0x1IllIl] = string.char(bxor_0xlII1II(b_0x1lI111, kb_0xl11IlI))
    end
    return table.concat(r_0xlIllIl)
end


local function getkeys_0xI1lll1()
    local seed = b64_0xIl1IIl.dec_0xl11lIl("U2FEV2FwMW4=")
    local k1_enc = b64_0xIl1IIl.dec_0xl11lIl("NwIHOAIXdj0=")
    local k2_enc = b64_0xIl1IIl.dec_0xl11lIl("IhcRBVIUASc=")
    return bxor_str_0xIlIIlI(k1_enc, seed), bxor_str_0xIlIIlI(k2_enc, seed)
end


local function cff_0x1l1IIl(a_0xlll1ll)
    local st_0xIIll11 = 0
    local res_0xIllll1 = a_0xlll1ll
    while true do
        if st_0xIIll11 == 0 then
            res_0xIllll1 = res_0xIllll1 + 1
            st_0xIIll11 = 1
        elseif st_0xIIll11 == 1 then
            res_0xIllll1 = res_0xIllll1 * 2
            st_0xIIll11 = 2
        elseif st_0xIIll11 == 2 then
            res_0xIllll1 = res_0xIllll1 - 3
            st_0xIIll11 = 3
        else
            break
        end
    end
    return res_0xIllll1
end


local function chain_0xII1III(x) return x*2 end
local function chain_0x1l1l1l(x) return chain_0xII1III(x)+1 end


local d_0xllIlI1 = {
  {op=255, val="", is_enc=true},
}
local pc_0xlllIIl = 1
local stk_0xIIlIll = {}
stk_0xIIlIll._jmp = nil


local disp_0xll1III = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xI1lll1()

local state_0xIIlI1l = 0
while true do
    if state_0xIIlI1l == 0 then  -- FETCH
        if pc_0xlllIIl > #d_0xllIlI1 then break end
        local inst = d_0xllIlI1[pc_0xlllIIl]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIl1IIl.dec_0xl11lIl(val)
            d = bxor_str_0xIlIIlI(d, k2)
            val = bxor_str_0xIlIIlI(d, k1)
        end
        stk_0xIIlIll._jmp = nil
        pc_0xlllIIl = pc_0xlllIIl + 1
        cur_op_0x1lIIIl = opcode
        cur_val_0x1lIllI = val
        state_0xIIlI1l = 1

    elseif state_0xIIlI1l == 1 then  -- EXECUTE
        local handler = disp_0xll1III[cur_op_0x1lIIIl]
        if handler then
            handler(stk_0xIIlIll, cur_val_0x1lIllI)
        end
        if stk_0xIIlIll._jmp then
            pc_0xlllIIl = pc_0xlllIIl + stk_0xIIlIll._jmp
        end
        state_0xIIlI1l = 0
